import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getDashboardStats, getMyTasks, getTasks } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { format, isPast } from 'date-fns';

const StatusBadge = ({ status }) => (
  <span className={`badge badge-${status}`}>{status.replace('-', ' ')}</span>
);
const PriorityBadge = ({ priority }) => (
  <span className={`badge badge-${priority}`}>{priority}</span>
);

export default function Dashboard() {
  const { user, isAdmin } = useAuth();
  const [stats, setStats] = useState(null);
  const [recentTasks, setRecentTasks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [statsRes, tasksRes] = await Promise.all([
          getDashboardStats(),
          isAdmin ? getTasks() : getMyTasks()
        ]);
        setStats(statsRes.data.stats);
        setRecentTasks((tasksRes.data.tasks || []).slice(0, 5));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [isAdmin]);

  if (loading) return <div className="loader-full"><div className="spinner" /></div>;

  const statCards = [
    { label: 'Total Tasks', value: stats?.total || 0, icon: '📋', color: 'var(--accent)' },
    { label: 'In Progress', value: stats?.inProgress || 0, icon: '🔄', color: 'var(--info)' },
    { label: 'Completed', value: stats?.completed || 0, icon: '✅', color: 'var(--success)' },
    { label: 'Overdue', value: stats?.overdue || 0, icon: '⚠️', color: 'var(--danger)' },
  ];

  return (
    <div>
      <div className="page-header">
        <div>
          <h1>Dashboard</h1>
          <p style={{ color: 'var(--text2)', marginTop: 4 }}>Welcome back, {user?.name} 👋</p>
        </div>
        {isAdmin && (
          <Link to="/projects" className="btn btn-primary">+ New Project</Link>
        )}
      </div>

      {/* Stat cards */}
      <div className="grid-4" style={{ marginBottom: 28 }}>
        {statCards.map((s, i) => (
          <div key={i} className="stat-card" style={{ borderTop: `3px solid ${s.color}` }}>
            <div className="stat-icon">{s.icon}</div>
            <div className="stat-value" style={{ color: s.color }}>{s.value}</div>
            <div className="stat-label">{s.label}</div>
          </div>
        ))}
      </div>

      {/* Progress bar */}
      {stats?.total > 0 && (
        <div className="card" style={{ marginBottom: 24 }}>
          <h3 style={{ marginBottom: 16, fontSize: 15 }}>📊 Overall Progress</h3>
          <div style={{ display: 'flex', gap: 4, height: 12, borderRadius: 6, overflow: 'hidden' }}>
            {stats.todo > 0 && <div style={{ flex: stats.todo, background: 'var(--border)' }} title="To Do" />}
            {stats.inProgress > 0 && <div style={{ flex: stats.inProgress, background: 'var(--accent)' }} title="In Progress" />}
            {stats.review > 0 && <div style={{ flex: stats.review, background: 'var(--warning)' }} title="In Review" />}
            {stats.completed > 0 && <div style={{ flex: stats.completed, background: 'var(--success)' }} title="Completed" />}
          </div>
          <div style={{ display: 'flex', gap: 16, marginTop: 10, flexWrap: 'wrap' }}>
            {[
              { label: 'Todo', val: stats.todo, color: 'var(--border)' },
              { label: 'In Progress', val: stats.inProgress, color: 'var(--accent)' },
              { label: 'Review', val: stats.review, color: 'var(--warning)' },
              { label: 'Completed', val: stats.completed, color: 'var(--success)' },
            ].map(item => (
              <div key={item.label} style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12 }}>
                <div style={{ width: 10, height: 10, borderRadius: '50%', background: item.color }} />
                <span style={{ color: 'var(--text2)' }}>{item.label}: <strong style={{ color: 'var(--text)' }}>{item.val}</strong></span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Recent tasks */}
      <div className="card">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <h3 style={{ fontSize: 15 }}>🕐 Recent Tasks</h3>
          <Link to={isAdmin ? '/tasks' : '/my-tasks'} style={{ fontSize: 13, color: 'var(--accent)' }}>View all →</Link>
        </div>
        {recentTasks.length === 0 ? (
          <div className="empty-state">
            <div className="icon">📭</div>
            <p>No tasks yet</p>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {recentTasks.map(task => (
              <div key={task._id} style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                padding: '12px 16px', background: 'var(--bg3)', borderRadius: 8,
                border: '1px solid var(--border)'
              }}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{task.title}</div>
                  <div style={{ fontSize: 12, color: 'var(--text2)', marginTop: 4 }}>
                    {task.project?.name} {task.assignedTo && `• ${task.assignedTo.name}`}
                  </div>
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexShrink: 0 }}>
                  {task.deadline && isPast(new Date(task.deadline)) && task.status !== 'completed' && (
                    <span className="badge badge-overdue">Overdue</span>
                  )}
                  <StatusBadge status={task.status} />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
